    if (str == NULL) {
        return NULL;
    }

    while (*str != '\0' && isspace((unsigned char)*str)) {
        str++;
    }

    if (*str == '\0') {
        return str;
    }

    end = str + strlen(str) - 1;
    while (end > str && isspace((unsigned char)*end)) {
        *end = '\0';
        end--;
    }

    return str;
}

/*
 * Copy src into dest only if it fits, always ensuring NUL termination.
 * Returns 0 on success, -1 on failure.
 */
static int safe_copy(char* dest, size_t dest_size, const char* src)
{
    size_t len;

    if (dest == NULL || src == NULL || dest_size == 0U) {
        return -1;
    }

    len = strlen(src);
    if (len >= dest_size) {
        return -1;
    }

    memcpy(dest, src, len + 1U);
    return 0;
}

/*
 * Parse a strictly valid decimal integer in range of int.
 * Returns 0 on success, -1 on failure.
 */
static int parse_int_strict(const char* str, int* out_value)
{
    long value;
    char extra;

    if (str == NULL || out_value == NULL) {
        return -1;
    }

    /*
     * Use sscanf as requested by context, while ensuring:
     * - full-string consumption
     * - valid integer format
     * - int range check
     */
    if (sscanf(str, " %ld %c", &value, &extra) != 1) {
        return -1;
    }

    if (value < 0L || value > (long)INT_MAX) {
        return -1;
    }

    *out_value = (int)value;
    return 0;
}

int parse_vm_config(const char* config_line, struct vm_hardware_config* hw_config)
{
    size_t input_len;
    char* buffer;
    char* token;
    char* saveptr;
    int cpu_found = 0;
    int memory_found = 0;
    int disk_found = 0;
    int network_found = 0;

    if (config_line == NULL || hw_config == NULL) {
        return -1;
    }

    if (*config_line == '\0') {
        return -1;
    }

    input_len = strlen(config_line);
    if (input_len == 0U) {
        return -1;
    }

    buffer = (char*)malloc(input_len + 1U);
    if (buffer == NULL) {
        return -1;
    }

    memcpy(buffer, config_line, input_len + 1U);

    hw_config->cpu_model[0] = '\0';
    hw_config->memory_mb = 0;
    hw_config->disk_path[0] = '\0';
    hw_config->network_adapter[0] = '\0';

    saveptr = NULL;
    token = strtok_r(buffer, ",", &saveptr);

    while (token != NULL) {
        char* key;
        char* value;
        char* equals;

        token = trim_whitespace(token);
        if (token == NULL || *token == '\0') {
            free(buffer);
            return -1;
        }

        equals = strchr(token, '=');
        if (equals == NULL) {
            free(buffer);
            return -1;
        }

        *equals = '\0';
        key = trim_whitespace(token);
        value = trim_whitespace(equals + 1);

        if (key == NULL || value == NULL || *key == '\0' || *value == '\0') {
            free(buffer);
            return -1;
        }

        if (strcmp(key, "cpu_model") == 0) {
            if (cpu_found || safe_copy(hw_config->cpu_model, sizeof(hw_config->cpu_model), value) != 0) {
                free(buffer);
                return -1;
            }
            cpu_found = 1;
        } else if (strcmp(key, "memory_mb") == 0) {
            int parsed_memory;

            if (memory_found || parse_int_strict(value, &parsed_memory) != 0) {
                free(buffer);
                return -1;
            }

            hw_config->memory_mb = parsed_memory;
            memory_found = 1;
        } else if (strcmp(key, "disk_path") == 0) {
            if (disk_found || safe_copy(hw_config->disk_path, sizeof(hw_config->disk_path), value) != 0) {
                free(buffer);
                return -1;
            }
            disk_found = 1;
        } else if (strcmp(key, "network_adapter") == 0) {
            if (network_found || safe_copy(hw_config->network_adapter, sizeof(hw_config->network_adapter), value) != 0) {
                free(buffer);
                return -1;
            }
            network_found = 1;
        } else {
            free(buffer);
            return -1;
        }

        token = strtok_r(NULL, ",", &saveptr);
    }

    free(buffer);

    if (!cpu_found || !memory_found || !disk_found || !network_found) {
        hw_config->cpu_model[0] = '\0';
        hw_config->memory_mb = 0;
        hw_config->disk_path[0] = '\0';
        hw_config->network_adapter[0] = '\0';
        return -1;
    }

    return 0;
}
